mapper.insert:
INSERT INTO TB_SEND_LOG (
    LOG_CD
  , SEND_TYPE
  , RECV_NM
  , RECV_ADDR
  , SEND_TITLE
  , SEND_CONTENT
  , SEND_RSLT
  , ERR_MSG
  , REF_CD
  , CRE_USR_CD
  , CRE_DTM
) VALUES (
    REPLACE(UUID(), '-', '')
  , #{sendType}
  , #{recvNm}
  , #{recvAddr}
  , #{sendTitle}
  , #{sendContent}
  , #{sendRslt}
  , #{errMsg}
  , #{refCd}
  , #{creUsrCd}
  , NOW()
)
